#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d(const T *in,
            T *out,
            const int input_width,
            const int mask_width,
            const T *mask)
{
  #pragma omp target
  {
    #pragma omp teams distribute parallel for
    for (int i = 0; i < input_width; i++) {
      T s = 0;
      int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (start + j >= 0 && start + j < input_width) {
          s += in[start + j] * mask[j];
        }
      }
      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled(const T *in,
                  T *out,
                  const int input_width,
                  const int mask_width,
                  const T *mask,
                  int block_size)
{
  int num_blocks = input_width / block_size;
  int n = mask_width / 2;

  #pragma omp target
  {
    #pragma omp teams distribute parallel for
    for (int block = 0; block < num_blocks; block++) {
      T tile[block_size + mask_width - 1];

      int block_start = block * block_size;

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          tile[n + t] = in[i];
        }
      }

      for (int t = block_size - n; t < block_size; t++) {
        int halo_left = (block - 1) * block_size + t;
        tile[t - (block_size - n)] = halo_left < 0 ? 0 : in[halo_left];
      }

      for (int t = 0; t < n; t++) {
        int halo_right = (block + 1) * block_size + t;
        tile[t + block_size + n] = halo_right >= input_width ? 0 : in[halo_right];
      }

      #pragma omp barrier

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          T s = 0;
          for (int j = 0; j < mask_width; j++) {
            s += tile[t + j] * mask[j];
          }
          out[i] = s;
        }
      }
    }
  }
}

template<typename T>
void conv1d_tiled_caching(const T *in,
                          T *out,
                          const int input_width,
                          const int mask_width,
                          const T *mask,
                          int block_size)
{
  int num_blocks = input_width / block_size;

  #pragma omp target
  {
    #pragma omp teams distribute parallel for
    for (int block = 0; block < num_blocks; block++) {
      T tile[block_size];

      int block_start = block * block_size;
      int next_tile_start = (block + 1) * block_size;

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          tile[t] = in[i];
        }
      }

      #pragma omp barrier

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          int start = i - (mask_width / 2);
          T s = 0;
          for (int j = 0; j < mask_width; j++) {
            int in_index = start + j;
            if (in_index >= 0 && in_index < input_width) {
              if (in_index >= block_start && in_index < next_tile_start) {
                s += tile[t + j - (mask_width / 2)] * mask[j];
              } else {
                s += in[in_index] * mask[j];
              }
            }
          }
          out[i] = s;
        }
      }
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b, *d_mask;
  d_a = (T *)omp_target_alloc(size_bytes, omp_get_default_device());
  d_b = (T *)omp_target_alloc(size_bytes, omp_get_default_device());
  d_mask = (T *)omp_target_alloc(mask_width * sizeof(T), omp_get_default_device());

  #pragma omp target copyin(a[0:input_width])
  {
    for (int i = 0; i < input_width; i++) {
      d_a[i] = a[i];
    }
  }

  #pragma omp target copyin(h_mask[0:mask_width])
  {
    for (int i = 0; i < mask_width; i++) {
      d_mask[i] = h_mask[i];
    }
  }

  #pragma omp target synchronize

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d(d_a, d_b, input_width, mask_width, d_mask);
    }
    #pragma omp target synchronize
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled(d_a, d_b, input_width, mask_width, d_mask, bs);
    }
    #pragma omp target synchronize
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching(d_a, d_b, input_width, mask_width, d_mask, bs);
    }
    #pragma omp target synchronize
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, omp_get_default_device());
  omp_target_free(d_b, omp_get_default_device());
  omp_target_free(d_mask, omp_get_default_device());
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width); 

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
